import{_ as a,o as e,c as r,a4 as l}from"./chunks/framework.BybBnFXO.js";const c=JSON.parse('{"title":"硫化物","description":"","frontmatter":{"title":"硫化物","mineralGroup":"sulfides"},"headers":[],"relativePath":"zh/mineral-groups/sulfides.md","filePath":"zh/mineral-groups/sulfides.md","lastUpdated":1784176423000}'),o={name:"zh/mineral-groups/sulfides.md"};function i(s,t,d,n,h,u){return e(),r("div",null,[...t[0]||(t[0]=[l('<h1 id="硫化物" tabindex="-1">硫化物 <a class="header-anchor" href="#硫化物" aria-label="Permalink to &quot;硫化物&quot;">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>硫化物类宝石以光学效应与金属光泽著称：</p><ul><li><strong>黄铁矿</strong>：FeS₂，&quot;愚人金&quot;，立方晶系，常用于装饰品</li><li><strong>闪锌矿</strong>：ZnS，色散极高（0.156），超过钻石</li><li><strong>方铅矿</strong>：PbS，重且软（Mohs 2.5），少见作宝石</li><li><strong>辰砂（朱砂）</strong>：HgS，红色，矿物学重要</li></ul><h2 id="化学式类型" tabindex="-1">化学式类型 <a class="header-anchor" href="#化学式类型" aria-label="Permalink to &quot;化学式类型&quot;">​</a></h2><p>M_xS_y (含 S²⁻)</p><h2 id="结构" tabindex="-1">结构 <a class="header-anchor" href="#结构" aria-label="Permalink to &quot;结构&quot;">​</a></h2><p>金属阳离子与 S²⁻ 形成离子键或共价键。常见结构包括 NaCl 型 （方铅矿）、闪锌矿型（ZnS 四面体配位）、黄铁矿型（FeS₂ 哑 铃状 S₂²⁻）。</p><h2 id="代表性宝石" tabindex="-1">代表性宝石 <a class="header-anchor" href="#代表性宝石" aria-label="Permalink to &quot;代表性宝石&quot;">​</a></h2><table tabindex="0"><thead><tr><th>宝石</th><th>化学式</th><th>亚族</th></tr></thead><tbody><tr><td>Pyrite / 黄铁矿</td><td>FeS₂</td><td>pyrite</td></tr><tr><td>Sphalerite / 闪锌矿</td><td>ZnS</td><td>sphalerite</td></tr></tbody></table><p><em>详见<a href="./intro.html">矿物组总览</a>。</em></p>',11)])])}const _=a(o,[["render",i]]);export{c as __pageData,_ as default};
